const requireAuth = (req, res, next) => {
  const token = req.headers.authorization?.replace(/^Bearer\s+/i, '');
  if (!token || !isValidToken(token)) return res.sendStatus(401);
  req.user = decodeToken(token);
  next();
};
app.get('/users', requireAuth, (req, res) => { /* ... */ });
```

### 2. No security headers (A05: Security Misconfiguration)
Express responses lack `X-Content-Type-Options`, `X-Frame-Options`, `Strict-Transport-Security`, CSP, etc.

```js
const helmet = require('helmet');
app.use(helmet());
```

### 3. No rate limiting (A04: Insecure Design / DoS)
Both routes are unbounded. Add a limiter before any endpoint is exposed publicly.

```js
const rateLimit = require('express-rate-limit');
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
```

### 4. No CORS policy (A05)
Default Express has no `Access-Control-Allow-Origin`, but if you later add `cors()` unconfigured, it will default to `*`. Set an explicit allowlist.

```js
const cors = require('cors');
app.use(cors({ origin: ['https://your-frontend.example'], credentials: true }));
```

### 5. Listening on all interfaces with no TLS (A02: Cryptographic Failures)
`app.listen(3000)` binds to `0.0.0.0` by default and serves plaintext HTTP. In production, terminate TLS at a reverse proxy and bind to localhost:

```js
const port = process.env.PORT || 3000;
app.listen(port, '127.0.0.1', () => console.log(`listening on ${port}`));
```

Also move the port to an env var so it's not hardcoded.

### 6. Verbose error handling is missing (A09: Logging/Monitoring; A05)
There is no `app.use((err, req, res, next) => …)` handler. Express's default will leak stack traces in dev mode. Add an explicit handler and a request logger:

```js
